import React from 'react';

import ContainerButton from './containerButton';

import './parser.css';

import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faHtml5, faMarkdown } from '@fortawesome/free-brands-svg-icons';
import { faFile, faUpload, faQuestionCircle, faFilePdf, faExpand, faCompress } from '@fortawesome/free-solid-svg-icons';

const Parser = () => {
	return (
		<div className='block'>
			<div className='section-one'>
				<button className='icon'><FontAwesomeIcon icon={faFile} /></button>
				<button className='icon'><FontAwesomeIcon icon={faUpload} /></button>
				<button className='icon'><FontAwesomeIcon icon={faQuestionCircle} /></button>
				<ContainerButton />
				{/*<button className='icon'><FontAwesomeIcon icon={faCompress} /></button>*/}
			</div>

			<div className='section-two'>
				<div className="left">
					<p>Document Name</p>
					<input type='text' id='doc-title' defaultValue='Untitled Document' />
				</div>

				<div className="right">
					<p>Export as:</p>
					<button className='icon'><FontAwesomeIcon icon={faHtml5} /></button>
					<button className='icon'><FontAwesomeIcon icon={faFilePdf} /></button>
					<button className='icon'><FontAwesomeIcon icon={faMarkdown} /></button>
				</div>
			</div>
		</div>
	)
}

export default Parser;
